export const TOPICS_E = [
  // ── TK–2 ───────────────────────────────────────────────────────────────────
  { id:'number-decomposition', title:'Decomposing Numbers', grade:'tk2', gradeLabel:'TK–2', subject:'arithmetic', tags:['decompose','break apart','different ways','flexibility'], summary:'Find multiple ways to break a number into parts.', intro:'Numbers can be broken into parts in many ways. This builds math flexibility.', steps:[{title:'Choose a number',body:'8 can be broken as: 1+7, 2+6, 3+5, 4+4, 5+3, 6+2, 7+1, 8+0.'},{title:'Use objects',body:'Put 8 counters into two groups. How many ways?'},{title:'Record all ways',body:'List all addend pairs systematically.'},{title:'Bridge to algebra',body:'8=?+5 — finding the unknown is a missing addend problem.'}], explanation:'Flexible number decomposition is the foundation of mental arithmetic.', exercises:[{question:'How many ways to decompose 6 into 2 parts?',answer:'7 ways (0+6 through 6+0)',hint:'Include 0 as a part.'},{question:'10=3+_',answer:'7',hint:'10-3=7.'},{question:'Decompose 12 three different ways.',answer:'6+6, 7+5, 8+4 (any valid pair)',hint:'Many correct answers.'}]},
  { id:'addition-properties-basic', title:'Properties of Addition (Basic)', grade:'tk2', gradeLabel:'TK–2', subject:'arithmetic', tags:['commutative','identity','addition','zero','swap'], summary:'Learn the commutative property and identity property of addition.', intro:'Swapping addends gives the same sum. Adding zero changes nothing.', steps:[{title:'Commutative property',body:'3+5=8 and 5+3=8. Order does not matter in addition.'},{title:'Identity property',body:'7+0=7. Adding zero gives the same number.'},{title:'Why this helps',body:'4+9 is harder than 9+4. Start with the bigger number!'},{title:'Zero hero',body:'Zero in addition is called the additive identity.'}], explanation:'These properties reduce the number of facts to memorize by half.', exercises:[{question:'Rewrite to make easier: 2+8.',answer:'Already easy! 8+2=10',hint:'Either order is fine; pick what\'s easier.'},{question:'___ + 0 = 15',answer:'15',hint:'Identity: adding 0 changes nothing.'},{question:'True or false: 6+4 = 4+6.',answer:'True',hint:'Commutative property.'}]},
  { id:'size-comparison', title:'Comparing Size and Weight', grade:'tk2', gradeLabel:'TK–2', subject:'arithmetic', tags:['compare','heavier','lighter','taller','shorter','longer'], summary:'Use comparison language to describe size and weight relationships.', intro:'We compare objects using words: heavier/lighter, taller/shorter, longer/shorter.', steps:[{title:'Direct comparison',body:'Hold one object in each hand. Which feels heavier?'},{title:'Indirect comparison',body:'Use a balance scale, ruler, or reference object.'},{title:'Relative language',body:'"The book is heavier than the pencil. The pencil is lighter than the book."'},{title:'Ordering three objects',body:'Shortest → middle → tallest.'}], explanation:'Comparison and measurement develop logical reasoning and lay groundwork for data analysis.', exercises:[{question:'Paper clip vs ruler — which is longer?',answer:'Ruler',hint:'Visual comparison.'},{question:'Book weighs 500g, pencil 8g. Which is heavier?',answer:'Book',hint:'500 > 8.'},{question:'Order from shortest to tallest: 45cm, 30cm, 60cm.',answer:'30, 45, 60',hint:'Ascending order.'}]},
  { id:'place-value-two-digit', title:'Two-Digit Place Value', grade:'tk2', gradeLabel:'TK–2', subject:'arithmetic', tags:['tens ones','two digit','place value','digits','compose'], summary:'Understand that two-digit numbers are composed of tens and ones.', intro:'Every two-digit number = some tens + some ones. 47 = 4 tens and 7 ones = 40 + 7.', steps:[{title:'Tens and ones',body:'Circle groups of 10. Remaining = ones.'},{title:'Draw',body:'Show 34 as 3 long rods (tens) and 4 small cubes (ones).'},{title:'Exchange',body:'10 ones = 1 ten. 20 = 2 tens and 0 ones.'},{title:'Write',body:'47 = 40 + 7. Tens digit = 4. Ones digit = 7.'}], explanation:'Two-digit place value is the foundation for all multi-digit arithmetic and beyond.', exercises:[{question:'32 = ___ tens and ___ ones',answer:'3 tens and 2 ones',hint:'3 is in the tens place.'},{question:'5 tens and 6 ones = ?',answer:'56',hint:'50+6=56.'},{question:'What number has 9 tens and 0 ones?',answer:'90',hint:'90+0=90.'}]},
  { id:'number-sense-0-1000', title:'Number Sense to 1000', grade:'tk2', gradeLabel:'TK–2', subject:'arithmetic', tags:['hundreds','1000','place value','number sense'], summary:'Read, write, and compare numbers to 1000.', intro:'After 100 comes 200, 300... all the way to 1000. Understanding hundreds extends place value.', steps:[{title:'Hundreds place',body:'3 hundreds = 300. In 342: 3 hundreds, 4 tens, 2 ones.'},{title:'Counting by hundreds',body:'100, 200, 300, 400, 500, 600, 700, 800, 900, 1000.'},{title:'Write in expanded form',body:'735 = 700+30+5.'},{title:'Compare three-digit numbers',body:'Compare hundreds first, then tens, then ones.'}], explanation:'Three-digit numbers follow the same place-value pattern as two-digit numbers.', exercises:[{question:'What is the value of 8 in 815?',answer:'800',hint:'8 is in the hundreds place.'},{question:'Write 400+60+3 as a number.',answer:'463',hint:'Combine all places.'},{question:'Compare: 523 __ 532',answer:'<',hint:'Tens: 2 < 3.'}]},
  { id:'basic-subtraction-word-problems', title:'Subtraction Word Problems', grade:'tk2', gradeLabel:'TK–2', subject:'arithmetic', tags:['subtract','word problem','take away','difference','compare'], summary:'Solve three types of subtraction word problems: take away, missing part, comparison.', intro:'Subtraction word problems come in three types: take away, find a missing part, or compare.', steps:[{title:'Take away',body:'"Had 12 marbles, lost 5." → 12-5=7.'},{title:'Missing part',body:'"Had some apples, gave 3, now have 8." → 8+3=11.'},{title:'Comparison',body:'"Ann has 9, Ben has 6. How many more does Ann have?" → 9-6=3.'},{title:'Key words',body:'"Left, remain, fewer, difference, more, how many more."'}], explanation:'All three structures model different real situations but all use subtraction.', exercises:[{question:'Had 15 stickers, gave away 7. How many left?',answer:'8',hint:'15-7=8.'},{question:'Tom scored 20, Jerry scored 14. How many more did Tom score?',answer:'6',hint:'20-14=6.'},{question:'Needed 30 cookies, baked 24. How many more to bake?',answer:'6',hint:'30-24=6.'}]},
  { id:'introduction-to-multiplication', title:'Introduction to Multiplication (Arrays and Groups)', grade:'tk2', gradeLabel:'TK–2', subject:'arithmetic', tags:['multiplication','groups of','array','repeated addition','rows columns'], summary:'Use repeated addition and arrays to introduce multiplication.', intro:'Multiplication is a shortcut for adding equal groups.', steps:[{title:'Equal groups',body:'3 bags with 4 apples each: 4+4+4=12. Or: 3×4=12.'},{title:'Array',body:'Draw 3 rows of 4 dots = 12 dots.'},{title:'Commutative',body:'3×4=12=4×3. The array works both ways.'},{title:'Write the multiplication sentence',body:'3×4=12: factor × factor = product.'}], explanation:'Multiplication is the gateway to arithmetic efficiency — every times table fact replaces repeated addition.', exercises:[{question:'5 groups of 3 = ?',answer:'15',hint:'3+3+3+3+3=15 or 5×3=15.'},{question:'Array: 2 rows, 7 columns.',answer:'14',hint:'2×7=14.'},{question:'Write as multiplication: 6+6+6+6.',answer:'4×6=24',hint:'4 groups of 6.'}]},
  { id:'data-collection', title:'Collecting and Recording Data', grade:'tk2', gradeLabel:'TK–2', subject:'statistics', tags:['data','survey','tally','record','organize'], summary:'Collect data through surveys and organize it using tally marks.', intro:'Data collection starts with a question and records answers systematically.', steps:[{title:'Ask a question',body:'"What is your favorite color: red, blue, or green?"'},{title:'Survey classmates',body:'Ask each person and record their answer.'},{title:'Tally marks',body:'Make one mark per answer. After 4, cross through with 5th: ||||.'},{title:'Count totals',body:'Count tallies for each category.'}], explanation:'Data collection and organization is the first step in statistical reasoning.', exercises:[{question:'15 tally marks for dogs, 8 for cats. Which is more popular?',answer:'Dogs',hint:'15 > 8.'},{question:'Tally for 12 responses: how many groups of 5?',answer:'2 complete groups (10) + 2 more',hint:'12=10+2.'},{question:'Why use tally marks instead of writing numbers?',answer:'Faster to record and count in real time',hint:'One mark per response.'}]},
  { id:'graphs-bar-pictograph', title:'Bar Graphs and Pictographs', grade:'tk2', gradeLabel:'TK–2', subject:'statistics', tags:['bar graph','pictograph','interpret','data display'], summary:'Create and read bar graphs and pictographs.', intro:'Graphs show data visually. Bar graphs use bar heights; pictographs use picture symbols.', steps:[{title:'Bar graph',body:'x-axis: categories. y-axis: counts. Height = quantity.'},{title:'Pictograph',body:'Each picture symbol represents a quantity (given in the key).'},{title:'Compare categories',body:'Which bar is tallest? Which symbol has most pictures?'},{title:'Find total',body:'Add all bar heights or picture counts.'}], explanation:'Visual data representations allow rapid comparison — our visual system is faster than our verbal system.', exercises:[{question:'Bar: cats=5, dogs=9. Difference?',answer:'4',hint:'9-5=4.'},{question:'Pictograph: each star=3 votes. 4 stars = ?',answer:'12 votes',hint:'4×3=12.'},{question:'Total from bar graph: 7,4,5,8.',answer:'24',hint:'7+4+5+8=24.'}]},
  { id:'counting-to-1000', title:'Counting to 1000', grade:'tk2', gradeLabel:'TK–2', subject:'arithmetic', tags:['count','1000','hundreds','patterns','skip count'], summary:'Count forward and backward by 1s, 10s, and 100s to 1000.', intro:'Counting to 1000 uses the same patterns as counting to 100, extended to hundreds.', steps:[{title:'Count by 1s',body:'…997, 998, 999, 1000.'},{title:'Count by 10s',body:'10, 20, 30, … 990, 1000.'},{title:'Count by 100s',body:'100, 200, 300, … 1000.'},{title:'Identify patterns',body:'The tens and ones digits cycle; the hundreds increase by one.'}], explanation:'Counting to 1000 builds the number sense needed for multiplication and place value.', exercises:[{question:'Count by 100s from 300 to 700.',answer:'300, 400, 500, 600, 700',hint:'Add 100 each time.'},{question:'What comes before 1000?',answer:'999',hint:'One less.'},{question:'Skip count by 10s from 760 to 800.',answer:'760, 770, 780, 790, 800',hint:'Add 10 each step.'}]},

  // ── Grades 3–5 ─────────────────────────────────────────────────────────────
  { id:'geometry-quadrilateral-properties', title:'Quadrilateral Properties', grade:'35', gradeLabel:'3–5', subject:'geometry', tags:['parallel sides','right angles','equal sides','quadrilateral'], summary:'Identify quadrilaterals using properties: parallel sides, equal sides, right angles.', intro:'Each type of quadrilateral has unique properties. Properties overlap in a hierarchy.', steps:[{title:'Trapezoid',body:'Exactly one pair of parallel sides.'},{title:'Parallelogram',body:'Two pairs of parallel sides. Opposite sides equal.'},{title:'Rectangle',body:'Parallelogram + 4 right angles.'},{title:'Rhombus',body:'Parallelogram + 4 equal sides.'},{title:'Square',body:'Rectangle + rhombus.'}], explanation:'The quadrilateral family is an example of hierarchical classification in mathematics.', exercises:[{question:'Is every square also a rectangle?',answer:'Yes — it has all properties of a rectangle plus equal sides.',hint:'Square = special rectangle.'},{question:'Parallelogram with all right angles?',answer:'Rectangle',hint:'Right angles + parallelogram.'},{question:'Can a trapezoid be a parallelogram?',answer:'No — trapezoid has exactly 1 pair of parallel sides',hint:'Parallelogram has 2 pairs.'}]},
  { id:'reading-line-plots', title:'Line Plots', grade:'35', gradeLabel:'3–5', subject:'statistics', tags:['line plot','data','dot','spread','frequency'], summary:'Create and interpret line plots to analyze data distribution.', intro:'A line plot displays data as X marks above a number line — each X = one data value.', steps:[{title:'Draw number line',body:'Cover all data values.'},{title:'Mark Xs',body:'Each data point gets one X above its value.'},{title:'Read the plot',body:'Most Xs = mode. Spread = range. Gaps = no data there.'},{title:'Fractions on line plot',body:'Data can be fractions: measuring to ½ inch.'}], explanation:'Line plots show individual data points while preserving distribution shape.', exercises:[{question:'Xs at: 3,3,4,5,5,5,6. Mode?',answer:'5',hint:'Most Xs over 5.'},{question:'Xs from 2 to 9. Range?',answer:'7',hint:'9-2=7.'},{question:'2 Xs at 4, 4 Xs at 5, 1 X at 6. Total data points?',answer:'7',hint:'2+4+1=7.'}]},
  { id:'multiples-patterns', title:'Multiples and Multiplication Patterns', grade:'35', gradeLabel:'3–5', subject:'arithmetic', tags:['multiples','multiplication','patterns','skip count'], summary:'Identify multiples and use patterns to solve problems.', intro:'Multiples of 6 are: 6, 12, 18, 24, 30… (counting by 6s).', steps:[{title:'Define multiple',body:'A multiple is the result of multiplying a number by a positive integer. 3×1=3, 3×2=6, 3×3=9…'},{title:'List multiples',body:'Multiples of 8: 8,16,24,32,40,48,56,64,72,80…'},{title:'Common multiples',body:'Multiples of both 4 and 6: 12, 24, 36… LCM=12.'},{title:'Patterns',body:'Multiples of 5 end in 0 or 5. Multiples of 9: digit sum = 9.'}], explanation:'Recognizing multiples and their patterns makes mental arithmetic much faster.', exercises:[{question:'Is 45 a multiple of 9?',answer:'Yes',hint:'9×5=45.'},{question:'First three common multiples of 4 and 6.',answer:'12, 24, 36',hint:'LCM=12.'},{question:'Which of 19, 24, 35 is a multiple of 7?',answer:'None — 7×4=28, 7×5=35. So 35.',hint:'Check 35÷7=5.'}]},
  { id:'dividing-decimals', title:'Dividing Decimals', grade:'35', gradeLabel:'3–5', subject:'fractions', tags:['decimals','divide','move decimal','algorithm'], summary:'Divide decimals by whole numbers and by decimals.', intro:'Dividing decimals by whole numbers: divide normally and keep decimal in place.', steps:[{title:'Divide decimal by whole number',body:'1.8÷3: divide as 18÷3=6. One decimal place → 0.6.'},{title:'Divide decimal by decimal',body:'1.8÷0.3: multiply both by 10 → 18÷3=6.'},{title:'Move the decimal',body:'Multiplying divisor by power of 10 to make it whole. Do same to dividend.'},{title:'Check with multiplication',body:'0.6×3=1.8 ✓'}], explanation:'Dividing by a decimal is equivalent to multiplying by its reciprocal.', exercises:[{question:'2.4 ÷ 4 = ?',answer:'0.6',hint:'24÷4=6. One place → 0.6.'},{question:'4.5 ÷ 0.5 = ?',answer:'9',hint:'45÷5=9.'},{question:'0.8 ÷ 0.04 = ?',answer:'20',hint:'80÷4=20.'}]},
  { id:'equivalent-ratios-tables', title:'Ratio Tables', grade:'35', gradeLabel:'3–5', subject:'fractions', tags:['ratio table','equivalent ratios','proportion','scale'], summary:'Use ratio tables to find and organize equivalent ratios.', intro:'A ratio table organizes equivalent ratios in rows, making scaling easy.', steps:[{title:'Start with initial ratio',body:'2:3 (2 cups juice to 3 cups water).'},{title:'Scale up by multiplying both',body:'×2: 4:6. ×3: 6:9. ×4: 8:12.'},{title:'Scale down by dividing',body:'÷2: 1:1.5 (not always integer).'},{title:'Find missing value',body:'?:15 with ratio 2:3. 15÷3=5. 5×2=10.'}], explanation:'Ratio tables are a visual and organized way to solve proportion problems.', exercises:[{question:'Ratio 3:5. Fill table for 15 cups water.',answer:'9 cups juice',hint:'15÷5=3. 3×3=9.'},{question:'Ratio 4:7. Find first value when second=21.',answer:'12',hint:'21÷7=3. 4×3=12.'},{question:'Scale 2:3 to __:18.',answer:'12:18',hint:'×6.'}]},
  { id:'fractions-on-number-line-beyond-one', title:'Fractions Beyond 1 on Number Line', grade:'35', gradeLabel:'3–5', subject:'fractions', tags:['number line','fractions beyond 1','mixed numbers','improper'], summary:'Plot and compare fractions greater than 1 on a number line.', intro:'The number line extends past 1. Fractions like 5/3 land between 1 and 2.', steps:[{title:'Extend the number line',body:'Mark 0, 1, 2, 3… Divide each segment into equal parts.'},{title:'Plot improper fractions',body:'7/4: divide 0-1, 1-2 into fourths. 7 fourths = 1¾.'},{title:'Compare',body:'9/5 vs 11/6: convert to same denominator or decimals.'},{title:'Mixed numbers',body:'2⅓ is 2 and ⅓ — plot just past 2.'}], explanation:'Number lines make the continuity of rational numbers visible.', exercises:[{question:'Plot 11/4 on a number line.',answer:'Between 2 and 3, at the ¾ mark after 2',hint:'11/4=2¾.'},{question:'Compare 7/3 and 9/4.',answer:'7/3≈2.33 > 9/4=2.25',hint:'Convert to decimals.'},{question:'Name a mixed number between 3 and 4.',answer:'3½ or any 3+fraction',hint:'3 < 3½ < 4.'}]},
  { id:'volume-irregular', title:'Volume of Irregular 3D Shapes', grade:'35', gradeLabel:'3–5', subject:'geometry', tags:['volume','irregular','water displacement','estimate','unit cubes'], summary:'Estimate volume of irregular shapes using unit cubes or water displacement.', intro:'Irregular solids don\'t have simple formulas. Use estimation or displacement.', steps:[{title:'Unit cube packing',body:'Fill a box with unit cubes. Count to approximate irregular shape inside.'},{title:'Water displacement',body:'Volume of object = rise in water level × base area of container.'},{title:'Decompose',body:'Break into recognizable parts and add volumes.'},{title:'Over/under estimate',body:'Too many cubes fits = overestimate. Too few = underestimate.'}], explanation:'Water displacement was discovered by Archimedes — legend says he ran through the streets shouting "Eureka!"', exercises:[{question:'Object placed in 10×10 container raises water 3cm. Volume?',answer:'300 cm³',hint:'10×10×3=300.'},{question:'Irregular shape fits ~20 unit cubes. Volume?',answer:'≈20 cubic units',hint:'Direct count.'},{question:'How does a submarine control its depth?',answer:'By adjusting water in ballast tanks to change displacement',hint:'Buoyancy = displaced water weight.'}]},
  { id:'statistics-cluster-outlier', title:'Clusters, Gaps, and Outliers', grade:'35', gradeLabel:'3–5', subject:'statistics', tags:['cluster','outlier','gap','distribution','data'], summary:'Identify clusters, gaps, and outliers in data sets.', intro:'Clusters are where data groups together. Gaps are missing ranges. Outliers are far from the rest.', steps:[{title:'Cluster',body:'Most values between 40-50: a cluster.'},{title:'Gap',body:'No values between 30 and 40: a gap.'},{title:'Outlier',body:'A value at 95 when rest is 40-50: an outlier.'},{title:'Effect on mean',body:'Outliers pull the mean away from the cluster. Median is resistant to outliers.'}], explanation:'Outlier detection is critical in data science — spotting errors and unusual cases.', exercises:[{question:'Data: {20,21,22,23,80}. Outlier?',answer:'80',hint:'Far from the cluster 20-23.'},{question:'Does the outlier 80 raise or lower the mean?',answer:'Raises it',hint:'High outlier pulls mean up.'},{question:'Which measure is most affected by an outlier?',answer:'Mean',hint:'Mean changes; median stays near the center.'}]},
  { id:'inequalities-basic', title:'Basic Inequalities', grade:'35', gradeLabel:'3–5', subject:'algebra', tags:['inequality','greater than','less than','expression','compare'], summary:'Write and evaluate simple inequalities involving expressions.', intro:'An inequality compares two quantities that may not be equal.', steps:[{title:'Evaluate both sides',body:'Is 3×4 > 2×5? 12 > 10? Yes!'},{title:'Write the inequality',body:'Use >, <, or =.'},{title:'With variables',body:'If n=5: is 2n+1 > 10? 11>10. True.'},{title:'Check multiple values',body:'For what values of n is 2n+1>10? n>4.5, so n≥5 for integers.'}], explanation:'Inequalities describe ranges of solutions rather than single values.', exercises:[{question:'Is 5²  __ 4×6?',answer:'25 > 24',hint:'25 vs 24.'},{question:'For n=3: is 4n-2 > 10?',answer:'10>10? No — 4(3)-2=10=10, not greater.',hint:'4×3-2=10.'},{question:'Find all integers where 3n<18.',answer:'n ≤ 5',hint:'n<6, so integers: 1,2,3,4,5.'}]},
  { id:'two-step-word-problems', title:'Two-Step Word Problems', grade:'35', gradeLabel:'3–5', subject:'arithmetic', tags:['two step','word problem','equations','real world','multi operation'], summary:'Solve two-step word problems requiring two different operations.', intro:'Two-step problems need two separate calculations. Show both equations.', steps:[{title:'Step 1: First operation',body:'"Bought 3 boxes of 8 pens each, then gave 7 away." Step 1: 3×8=24 pens.'},{title:'Step 2: Second operation',body:'Step 2: 24-7=17 pens left.'},{title:'Write both equations',body:'3×8=24. 24-7=17.'},{title:'Answer the question',body:'"17 pens remain."'}], explanation:'Two-step problems build algebraic thinking — chains of operations model real situations.', exercises:[{question:'Earned $5/hour for 8 hours, then spent $18. Money left?',answer:'$22',hint:'8×5=40. 40-18=22.'},{question:'4 shelves with 12 books each. Removed 15. Books left?',answer:'33',hint:'48-15=33.'},{question:'Box holds 24 bottles. Filled 5 boxes, one was dropped and 7 broke. Unbroken?',answer:'113',hint:'5×24=120. 120-7=113.'}]},
  { id:'math-vocabulary', title:'Math Vocabulary Builder', grade:'35', gradeLabel:'3–5', subject:'arithmetic', tags:['vocabulary','terms','define','math language'], summary:'Learn and use precise mathematical vocabulary.', intro:'Mathematics has its own language. Using correct terms makes communication clear.', steps:[{title:'Operations',body:'Sum (add), difference (subtract), product (multiply), quotient (divide).'},{title:'Parts of operations',body:'Addend+addend=sum. Minuend-subtrahend=difference. Factor×factor=product. Dividend÷divisor=quotient.'},{title:'Number types',body:'Integer, fraction, decimal, percent, prime, composite.'},{title:'Geometry',body:'Vertex, edge, face, perimeter, area, volume, radius, diameter.'}], explanation:'Mathematical precision is the backbone of proof — ambiguous language creates errors.', exercises:[{question:'In 56÷7=8: what is the divisor?',answer:'7',hint:'The number you divide by.'},{question:'Name for the answer to a multiplication problem.',answer:'Product',hint:'Factor × factor = product.'},{question:'What do you call a polygon\'s corner?',answer:'Vertex (plural: vertices)',hint:'The point where sides meet.'}]},
  { id:'geometry-classify-triangles-angles', title:'Classifying Triangles', grade:'35', gradeLabel:'3–5', subject:'geometry', tags:['triangle','acute','right','obtuse','classify','angles'], summary:'Classify triangles by their angles as acute, right, or obtuse.', intro:'Every triangle is classified by its largest angle.', steps:[{title:'Acute triangle',body:'All three angles are less than 90°.'},{title:'Right triangle',body:'Exactly one angle equals 90°.'},{title:'Obtuse triangle',body:'Exactly one angle is greater than 90°.'},{title:'Check the sum',body:'All triangles: angles sum to 180°.'}], explanation:'The classification by angles determines whether the Pythagorean theorem applies (right only) or inequalities (others).', exercises:[{question:'Triangle with angles 50°, 60°, 70°. Type?',answer:'Acute',hint:'All less than 90°.'},{question:'Triangle with angles 90°, 45°, 45°. Type?',answer:'Right',hint:'One angle = 90°.'},{question:'Largest angle in a triangle is 110°. Type?',answer:'Obtuse',hint:'110° > 90°.'}]},
  { id:'fraction-division-fractions', title:'Dividing Fractions by Whole Numbers', grade:'35', gradeLabel:'3–5', subject:'fractions', tags:['divide fractions','whole number','share','reciprocal'], summary:'Divide a fraction by a whole number by multiplying by the reciprocal.', intro:'To divide a fraction by a whole number, multiply by 1/n.', steps:[{title:'Interpret',body:'½ ÷ 3 means: share ½ equally among 3 people. Each gets 1/6.'},{title:'Multiply by reciprocal',body:'½ ÷ 3 = ½ × 1/3 = 1/6.'},{title:'General rule',body:'a/b ÷ n = a/(bn).'}], explanation:'Dividing by n is the same as multiplying by 1/n — this is the definition of division.', exercises:[{question:'¾ ÷ 2 = ?',answer:'3/8',hint:'¾ × ½ = 3/8.'},{question:'2/3 ÷ 4 = ?',answer:'1/6',hint:'2/(3×4)=2/12=1/6.'},{question:'Share ⅗ of a pizza among 3. Each person gets?',answer:'1/5',hint:'(3/5)÷3=3/15=1/5.'}]},
  { id:'math-estimation-real-world', title:'Estimation in Real Life', grade:'35', gradeLabel:'3–5', subject:'arithmetic', tags:['estimation','real world','budget','time','rounding'], summary:'Apply estimation skills to everyday situations like shopping and time management.', intro:'Estimation is a life skill. A quick estimate helps you make decisions fast.', steps:[{title:'Shopping',body:'"$2.89+$4.15+$1.79" ≈ 3+4+2=$9. Check: enough money?'},{title:'Time',body:'"7 tasks taking ~8 minutes each" ≈ 56 minutes ≈ 1 hour.'},{title:'Distance',body:'Highway at ~60 mph. 185 miles ≈ 3 hours.'},{title:'Always compare',body:'Estimate before exact answer to catch errors.'}], explanation:'Engineering, medicine, and finance all rely on estimation before exact calculation.', exercises:[{question:'Estimate total: $3.49+$6.89+$2.10',answer:'≈$12.50',hint:'3.50+7+2=12.50.'},{question:'About how long for 9 tasks at ~12 min each?',answer:'≈1¾ hours',hint:'108 min ≈ 100 min ≈ 1:40.'},{question:'Estimate 247÷6.',answer:'≈40',hint:'240÷6=40.'}]},
  { id:'place-value-decimal-hundredths', title:'Hundredths as Decimals and Fractions', grade:'35', gradeLabel:'3–5', subject:'fractions', tags:['hundredths','decimals','fractions','0.01','place value'], summary:'Represent hundredths as both fractions and decimal notation.', intro:'0.01 = 1/100. Hundredths appear in money, measurements, and percentages.', steps:[{title:'Tenths',body:'0.1 = 1/10. Ten-by-ten grid: shade one column = 10 squares = 1/10.'},{title:'Hundredths',body:'0.01 = 1/100. Shade one small square = 1/100.'},{title:'Combined',body:'0.27 = 27/100 = 2 tenths + 7 hundredths.'},{title:'Money connection',body:'$0.07 = 7/100 of a dollar = 7 cents.'}], explanation:'Hundredths complete the decimal place-value system through the second place.', exercises:[{question:'Write 0.09 as a fraction.',answer:'9/100',hint:'Hundredths place.'},{question:'Write 37/100 as a decimal.',answer:'0.37',hint:'Tenths=3, hundredths=7.'},{question:'How many hundredths in 0.5?',answer:'50',hint:'0.5=50/100.'}]},
  { id:'multiplication-mental-math', title:'Mental Math Multiplication Strategies', grade:'35', gradeLabel:'3–5', subject:'arithmetic', tags:['mental math','strategy','multiply','doubles','halves','compensate'], summary:'Use doubling, halving, and compensation to multiply mentally.', intro:'Mental math strategies make multiplication faster without paper or calculator.', steps:[{title:'Doubling and halving',body:'24×5: halve 24→12, double 5→10. 12×10=120.'},{title:'Compensation',body:'19×7: 20×7=140, minus 7=133.'},{title:'Break apart',body:'16×14: 16×14=16×10+16×4=160+64=224.'},{title:'Multiplying by 11',body:'43×11: 4_3, middle digit=4+3=7: 473.'}], explanation:'These strategies use algebraic properties (distributive, associative) intuitively.', exercises:[{question:'25×8 using halving/doubling.',answer:'200',hint:'Halve 8→4, double 25→50. Or: 25×4×2.'},{question:'29×6 using compensation.',answer:'174',hint:'30×6-6=180-6=174.'},{question:'37×11=?',answer:'407',hint:'3_7, middle=3+7=10. Carry: 3+1=4. 407.'}]},
  { id:'number-line-operations', title:'Number Line Operations', grade:'35', gradeLabel:'3–5', subject:'arithmetic', tags:['number line','add','subtract','jump','arrow'], summary:'Use number line diagrams to model addition and subtraction.', intro:'A number line makes arithmetic visual — arrows show movement.', steps:[{title:'Addition = jump right',body:'45+28: start at 45. Jump +20=65. Jump +8=73.'},{title:'Subtraction = jump left',body:'73-28: start at 73. Jump -20=53. Jump -8=45.'},{title:'Decompose the second number',body:'Break 28 into 20+8 for easier jumps.'},{title:'Check',body:'End position = answer.'}], explanation:'Number line models build mental number-line visualization — a key number sense skill.', exercises:[{question:'Add on number line: 56+37.',answer:'93',hint:'56+30=86. 86+7=93.'},{question:'Subtract on number line: 84-46.',answer:'38',hint:'84-40=44. 44-6=38.'},{question:'Model -3+7 on a number line.',answer:'Start -3, jump +7, land at 4.',hint:'Right 7 from -3.'}]},
  { id:'geometry-transformations-basic', title:'Basic Transformations', grade:'35', gradeLabel:'3–5', subject:'geometry', tags:['translation','reflection','rotation','slide flip turn'], summary:'Describe translations (slides), reflections (flips), and rotations (turns).', intro:'Three basic transformations move shapes without changing their size or shape.', steps:[{title:'Translation (slide)',body:'Move shape left, right, up, down without turning or flipping.'},{title:'Reflection (flip)',body:'Mirror image across a line (line of reflection).'},{title:'Rotation (turn)',body:'Turn shape around a center point. 90°, 180°, 270°, 360°.'},{title:'Preserve shape and size',body:'All three are rigid motions — congruence is preserved.'}], explanation:'Transformations are the mathematical language of motion in geometry.', exercises:[{question:'Slide a shape 5 units right. Type of transformation?',answer:'Translation',hint:'Moving without rotating or flipping.'},{question:'Flip a shape over a vertical line. Type?',answer:'Reflection',hint:'Mirror image.'},{question:'Turn a shape 90° clockwise. Type?',answer:'Rotation',hint:'Rotating around a point.'}]},
  { id:'fractions-mixed-operations', title:'Mixed Fraction Operations', grade:'35', gradeLabel:'3–5', subject:'fractions', tags:['fractions','add subtract multiply','mixed review'], summary:'Practice all fraction operations: add, subtract, multiply, divide.', intro:'Fluency with fractions requires knowing which operation a problem needs and how to execute it.', steps:[{title:'Add/Subtract: find LCD',body:'1/3+1/4=4/12+3/12=7/12.'},{title:'Multiply: straight across',body:'2/3×3/5=6/15=2/5.'},{title:'Divide: KCF (Keep Change Flip)',body:'3/4÷1/2=3/4×2/1=6/4=3/2.'},{title:'Choose the operation',body:'"¾ of 20" → multiply. "¾ more than ½" → add. "Split ¾ among 3" → divide.'}], explanation:'All four fraction operations follow from the definition of fractions as division.', exercises:[{question:'5/6 - 1/4 = ?',answer:'7/12',hint:'LCD=12: 10/12-3/12.'},{question:'2/3 × 3/8 = ?',answer:'1/4',hint:'6/24=1/4.'},{question:'5/6 ÷ 5/12 = ?',answer:'2',hint:'5/6×12/5=2.'}]},

  // ── Grades 6–8 ─────────────────────────────────────────────────────────────
  { id:'rational-numbers-operations', title:'Operations with Rational Numbers', grade:'68', gradeLabel:'6–8', subject:'arithmetic', tags:['rational numbers','add subtract multiply divide','fractions decimals'], summary:'Perform all four operations with rational numbers including negatives.', intro:'Rational numbers include all fractions and their negatives. All arithmetic operations apply.', steps:[{title:'Adding negatives',body:'(-2/3)+(1/4)=-8/12+3/12=-5/12.'},{title:'Subtracting',body:'3/4-(-1/2)=3/4+1/2=5/4.'},{title:'Multiplying',body:'(-2/3)×(3/4)=-6/12=-1/2.'},{title:'Dividing',body:'(-3/5)÷(2/3)=(-3/5)×(3/2)=-9/10.'}], explanation:'The rules for signs combine with fraction rules: apply both simultaneously.', exercises:[{question:'(-1/2)+(3/4)=?',answer:'1/4',hint:'-2/4+3/4=1/4.'},{question:'(-2/3)×(-3/4)=?',answer:'1/2',hint:'Negative×negative=positive. 6/12=1/2.'},{question:'(5/6)÷(-1/3)=?',answer:'-5/2',hint:'5/6×(-3/1)=-15/6=-5/2.'}]},
  { id:'equations-fractions-decimals', title:'Equations with Fractions and Decimals', grade:'68', gradeLabel:'6–8', subject:'algebra', tags:['equations','fractions','decimals','multiply through','clear'], summary:'Solve equations containing fractions or decimals by clearing the fractions first.', intro:'Multiply every term by the LCD (or by 10/100) to eliminate fractions or decimals.', steps:[{title:'Clear fractions',body:'x/3+x/4=7. LCD=12. Multiply all: 4x+3x=84. 7x=84. x=12.'},{title:'Clear decimals',body:'0.3x+0.7=1.6. Multiply by 10: 3x+7=16. 3x=9. x=3.'},{title:'Check',body:'Always substitute back.'}], explanation:'Clearing fractions/decimals transforms complex equations into simple ones.', exercises:[{question:'x/2+x/3=5.',answer:'x=6',hint:'LCD=6: 3x+2x=30. 5x=30.'},{question:'0.5x-0.2=0.8',answer:'x=2',hint:'Multiply by 10: 5x-2=8.'},{question:'2/3x+1/6=1',answer:'x=3/4',hint:'LCD=6: 4x+1=6. x=5/4 — recheck: 4x=5? No. 2/3x=5/6. x=5/4.'}]},
  { id:'real-number-system', title:'The Real Number System', grade:'68', gradeLabel:'6–8', subject:'arithmetic', tags:['real numbers','rational','irrational','integers','whole','natural'], summary:'Classify numbers in the hierarchy of real numbers.', intro:'Real numbers include all rational and irrational numbers. They fill the entire number line.', steps:[{title:'Natural numbers',body:'1, 2, 3, 4… (counting numbers).'},{title:'Whole numbers',body:'0, 1, 2, 3… (include 0).'},{title:'Integers',body:'…-2,-1,0,1,2… (include negatives).'},{title:'Rationals',body:'Any p/q. Includes terminating and repeating decimals.'},{title:'Irrationals',body:'√2, π, e — non-repeating, non-terminating.'},{title:'All together = Real numbers',body:'Every point on the number line.'}], explanation:'The nested sets: Natural ⊂ Whole ⊂ Integers ⊂ Rational ⊂ Real.', exercises:[{question:'Classify -7.',answer:'Integer, rational, real',hint:'-7=-7/1.'},{question:'Classify √5.',answer:'Irrational, real',hint:'Not a perfect square.'},{question:'Is every integer rational?',answer:'Yes',hint:'n = n/1.'}]},
  { id:'angle-relationships-parallel', title:'Angles with Parallel Lines and Transversals', grade:'68', gradeLabel:'6–8', subject:'geometry', tags:['parallel lines','transversal','alternate interior','corresponding','co-interior'], summary:'Find angles formed when a transversal crosses parallel lines.', intro:'Parallel lines crossed by a transversal create specific angle relationships.', steps:[{title:'Corresponding angles',body:'Same position at each intersection. Equal. (F-shape pattern.)'},{title:'Alternate interior',body:'Between the parallels, opposite sides of transversal. Equal. (Z-shape.)'},{title:'Co-interior (same-side interior)',body:'Between parallels, same side. Supplementary (add to 180°).'},{title:'Alternate exterior',body:'Outside parallels, opposite sides. Equal.'}], explanation:'These relationships are the foundation of geometric proof.', exercises:[{question:'Corresponding angle to 65°?',answer:'65°',hint:'Corresponding = equal.'},{question:'Alternate interior angle to 110°?',answer:'110°',hint:'Alternate interior = equal.'},{question:'Co-interior angles if one is 70°?',answer:'110°',hint:'70+110=180.'}]},
  { id:'area-composite-figures-2', title:'Area of Composite Figures (Advanced)', grade:'68', gradeLabel:'6–8', subject:'geometry', tags:['composite area','circles','rectangles','triangles','combine'], summary:'Find areas of figures combining rectangles, triangles, and circles.', intro:'Complex shapes often combine rectangles, triangles, and circles.', steps:[{title:'Identify all components',body:'Semicircle on top of a rectangle.'},{title:'Calculate each',body:'Rectangle 8×4=32. Semicircle r=4: πr²/2=8π≈25.1.'},{title:'Add or subtract',body:'Total≈57.1.'},{title:'Careful with circular cutouts',body:'Rectangle minus circle: A_rect - πr².'}], explanation:'Composite area problems require combining all previously learned formulas.', exercises:[{question:'Rectangle 10×6 with semicircle of diameter 6 on top. Total area?',answer:'60+4.5π≈74.1',hint:'Circle r=3. Semicircle=4.5π.'},{question:'Circle radius 5, square 6×6 cut out from center. Remaining?',answer:'25π-36≈42.5',hint:'78.5-36.'},{question:'Triangle on top of rectangle: rectangle 8×4, triangle base 8, height 3. Total?',answer:'32+12=44',hint:'½×8×3=12.'}]},
  { id:'probability-independent-events', title:'Independent and Dependent Events', grade:'68', gradeLabel:'6–8', subject:'statistics', tags:['independent','dependent','probability','with without replacement'], summary:'Calculate probabilities for independent and dependent events.', intro:'Independent: one event doesn\'t affect the other. Dependent: first event changes the second.', steps:[{title:'Independent',body:'P(A and B)=P(A)×P(B). Flip coin, roll die: 1/2×1/6=1/12.'},{title:'Dependent: without replacement',body:'Bag of 4 red, 6 blue. Draw two. P(both red)=4/10×3/9=12/90=2/15.'},{title:'Test independence',body:'Does P(A) change after B occurs? If yes, dependent.'}], explanation:'Conditional probability quantifies dependence: P(A|B)=P(A∩B)/P(B).', exercises:[{question:'P(red) twice with replacement from {3R,7B}?',answer:'9/100',hint:'3/10×3/10=9/100.'},{question:'Without replacement from {3R,7B}. P(RR)?',answer:'6/90=1/15',hint:'3/10×2/9.'},{question:'Are coin flips independent?',answer:'Yes — result of first flip doesn\'t affect second',hint:'Each flip: P(H)=1/2 always.'}]},
  { id:'intro-to-geometry-transformation-rules', title:'Transformation Rules in Coordinates', grade:'68', gradeLabel:'6–8', subject:'geometry', tags:['transformation','coordinate','rule','function notation'], summary:'Apply coordinate rules for translations, reflections, and rotations.', intro:'Transformations have algebraic rules using coordinate notation.', steps:[{title:'Translation (a,b)',body:'(x,y) → (x+a, y+b). Right a, up b.'},{title:'Reflection over x-axis',body:'(x,y) → (x,-y).'},{title:'Reflection over y-axis',body:'(x,y) → (-x,y).'},{title:'Rotation 90° CW',body:'(x,y) → (y,-x).'},{title:'Rotation 180°',body:'(x,y) → (-x,-y).'}], explanation:'Coordinate rules make transformations algebraic and computable.', exercises:[{question:'Translate (-2,3) by (5,-1).',answer:'(3,2)',hint:'(-2+5, 3-1).'},{question:'Reflect (4,-3) over y-axis.',answer:'(-4,-3)',hint:'x changes sign.'},{question:'Rotate (2,5) 90° CW.',answer:'(5,-2)',hint:'(x,y)→(y,-x).'}]},
  { id:'expressions-evaluating', title:'Evaluating Algebraic Expressions', grade:'68', gradeLabel:'6–8', subject:'algebra', tags:['evaluate','substitute','expression','variable','replace'], summary:'Substitute values for variables and evaluate algebraic expressions.', intro:'Evaluating means replacing variables with numbers and computing.', steps:[{title:'Substitute',body:'Evaluate 3x²-2x+1 for x=4: 3(16)-8+1=48-8+1=41.'},{title:'PEMDAS after substituting',body:'Follow order of operations after plugging in.'},{title:'Multiple variables',body:'Evaluate 2a+3b for a=5, b=2: 10+6=16.'},{title:'Check with estimation',body:'x≈4 in 3x²: 3×16≈48.'}], explanation:'Evaluating is how you test whether a value is a solution to an equation.', exercises:[{question:'Evaluate 4x-7 for x=3.',answer:'5',hint:'4(3)-7=5.'},{question:'Evaluate a²+b² for a=3, b=4.',answer:'25',hint:'9+16=25.'},{question:'Evaluate 2(x+y) for x=6, y=4.',answer:'20',hint:'2(10)=20.'}]},
  { id:'consumer-math', title:'Consumer Math: Tax, Tip, Discount', grade:'68', gradeLabel:'6–8', subject:'arithmetic', tags:['tax','tip','discount','consumer','percent'], summary:'Calculate sales tax, gratuity, and discounts on real purchases.', intro:'Practical money math: tax adds to price, discount subtracts, tip adds to a bill.', steps:[{title:'Sales tax',body:'$80 item, 8% tax: 80×0.08=$6.40. Total=$86.40.'},{title:'Tip',body:'$55 bill, 20% tip: 55×0.20=$11. Total=$66.'},{title:'Discount',body:'$120 item, 30% off: 120×0.30=$36 off. Sale price=$84.'},{title:'Sequential',body:'$100, 20% off then 8% tax: 80×1.08=$86.40.'}], explanation:'Consumer math is among the most important practical applications of percent.', exercises:[{question:'$45 meal + 15% tip. Total?',answer:'$51.75',hint:'45×1.15=51.75.'},{question:'$200 jacket, 25% discount. Sale price?',answer:'$150',hint:'200×0.75=150.'},{question:'$65, 7% tax. Total?',answer:'$69.55',hint:'65×1.07=69.55.'}]},
  { id:'statistics-mean-absolute', title:'Using Statistics to Compare Groups', grade:'68', gradeLabel:'6–8', subject:'statistics', tags:['mean','median','range','compare groups'], summary:'Use multiple statistics to compare two groups.', intro:'One statistic rarely tells the full story. Use mean, median, and range together.', steps:[{title:'Calculate all three for each group',body:'Group A: mean=72, median=70, range=20. Group B: mean=72, median=75, range=5.'},{title:'Same mean, different distribution',body:'Group B has higher median and smaller range — more consistently near 75.'},{title:'Context matters',body:'"Who performed better?" depends on whether you value average or consistency.'}], explanation:'Using multiple statistics prevents misleading conclusions from looking at only one measure.', exercises:[{question:'A: {50,70,80,90,100} B: {75,77,78,79,81}. Same mean (~78). Which is more consistent?',answer:'B — much smaller range (6 vs 50)',hint:'Range shows spread.'},{question:'Mean A=70, mean B=65. Can B have higher median?',answer:'Yes — if B has fewer high outliers',hint:'Outliers pull mean more than median.'},{question:'Report center for skewed data: mean or median?',answer:'Median — less affected by skew/outliers',hint:'Median is robust.'}]},

  // ── Grades 9–12 ────────────────────────────────────────────────────────────
  { id:'taylor-series-intro', title:'Taylor Series (Introduction)', grade:'912', gradeLabel:'9–12', subject:'calculus', tags:['Taylor series','Maclaurin','polynomial approximation','sin cos e^x'], summary:'Approximate functions using Taylor and Maclaurin series.', intro:'A Taylor series expresses a function as an infinite polynomial of derivatives at a point.', steps:[{title:'Maclaurin series',body:'f(x)=f(0)+f\'(0)x+f\'\'(0)x²/2!+f\'\'\'(0)x³/3!+…'},{title:'e^x series',body:'e^x=1+x+x²/2!+x³/3!+… Works for all x.'},{title:'sin(x) series',body:'sin(x)=x-x³/3!+x⁵/5!-… Alternating, odd powers.'},{title:'cos(x) series',body:'cos(x)=1-x²/2!+x⁴/4!-…'}], explanation:'Taylor series are the foundation of numerical computing — calculators use them internally.', exercises:[{question:'First 3 terms of e^x series.',answer:'1+x+x²/2',hint:'f(0)=1, f\'(0)=1, f\'\'(0)=1.'},{question:'Approximate sin(0.1) using 2 terms.',answer:'≈0.1-0.001/6≈0.09983',hint:'0.1-0.001/6.'},{question:'What is the Maclaurin series for cos(x)?',answer:'1-x²/2!+x⁴/4!-…',hint:'Even powers, alternating signs.'}]},
  { id:'complex-number-polar', title:'Complex Numbers in Polar Form', grade:'912', gradeLabel:'9–12', subject:'precalculus', tags:['complex polar','modulus','argument','De Moivre','Euler'], summary:'Represent complex numbers in polar form and apply De Moivre\'s theorem.', intro:'Every complex number a+bi can be written as r(cos θ + i sin θ) = re^(iθ).', steps:[{title:'Modulus',body:'r=|z|=√(a²+b²).'},{title:'Argument',body:'θ=arctan(b/a). Adjust for quadrant.'},{title:'Polar form',body:'z=r(cos θ+i sin θ).'},{title:'De Moivre',body:'z^n=r^n(cos(nθ)+i sin(nθ)). (2(cos30°+isin30°))³=8(cos90°+isin90°)=8i.'}], explanation:'Euler\'s formula e^(iπ)+1=0 connects e, π, i, 1, and 0 — considered the most beautiful equation.', exercises:[{question:'Polar form of 1+i.',answer:'√2(cos45°+i sin45°)',hint:'r=√2. θ=45°.'},{question:'(cos60°+i sin60°)².',answer:'cos120°+i sin120°=-1/2+i√3/2',hint:'De Moivre: double the angle.'},{question:'|3+4i|=?',answer:'5',hint:'√(9+16)=5.'}]},
  { id:'statistics-power-tests', title:'Power and Type I/II Errors', grade:'912', gradeLabel:'9–12', subject:'statistics', tags:['power','Type I error','Type II error','alpha','beta','hypothesis'], summary:'Understand the trade-off between Type I and Type II errors in hypothesis testing.', intro:'A Type I error rejects a true null hypothesis. A Type II error fails to reject a false one.', steps:[{title:'Type I error (α)',body:'False positive. P(Type I)=α=significance level. Rejecting H₀ when it\'s true.'},{title:'Type II error (β)',body:'False negative. P(Type II)=β. Failing to reject H₀ when it\'s false.'},{title:'Power = 1-β',body:'Probability of correctly rejecting a false H₀.'},{title:'Tradeoff',body:'Reducing α (more evidence needed) increases β. Use larger n to reduce both.'}], explanation:'Medical testing: Type I = false positive diagnosis. Type II = missed real disease.', exercises:[{question:'α=0.05 means?',answer:'5% chance of rejecting a true null (Type I error)',hint:'Significance level = Type I rate.'},{question:'Power=0.80. Meaning?',answer:'80% chance of detecting a real effect',hint:'Power=1-β.'},{question:'How does increasing sample size affect power?',answer:'Increases power (reduces β)',hint:'More data → more able to detect real effects.'}]},
  { id:'vectors-3d', title:'Vectors in 3D', grade:'912', gradeLabel:'9–12', subject:'precalculus', tags:['3D vectors','cross product','dot product','magnitude','component'], summary:'Extend vectors to 3D space and apply cross product.', intro:'3D vectors have three components. The cross product is unique to 3D.', steps:[{title:'3D components',body:'v=⟨a,b,c⟩. Magnitude=√(a²+b²+c²).'},{title:'Dot product',body:'u⃗·v⃗=a₁a₂+b₁b₂+c₁c₂. Scalar.'},{title:'Cross product',body:'u⃗×v⃗ = perpendicular to both. |u⃗×v⃗|=|u||v|sin θ.'},{title:'Applications',body:'Torque, magnetic force, area of parallelogram.'}], explanation:'The cross product is only defined in 3D (and 7D). It produces a vector perpendicular to both inputs.', exercises:[{question:'Magnitude of ⟨1,2,2⟩?',answer:'3',hint:'√(1+4+4)=3.'},{question:'Dot product of ⟨1,0,0⟩ and ⟨0,1,0⟩?',answer:'0',hint:'Perpendicular vectors dot to 0.'},{question:'Cross product of ⟨1,0,0⟩ and ⟨0,1,0⟩?',answer:'⟨0,0,1⟩',hint:'î×ĵ=k̂.'}]},
  { id:'number-theory-primes', title:'Advanced Number Theory', grade:'912', gradeLabel:'9–12', subject:'algebra', tags:['prime','Fermat','Euler','number theory','proof'], summary:'Explore Fermat\'s Little Theorem and applications in number theory.', intro:'Number theory studies the deep properties of integers, particularly primes.', steps:[{title:'Fermat\'s Little Theorem',body:'If p is prime: aᵖ ≡ a (mod p). Equivalently: aᵖ⁻¹ ≡ 1 (mod p) when gcd(a,p)=1.'},{title:'Application',body:'2⁶ mod 7: by FLT, 2⁶≡1 (mod 7). Verify: 64=9×7+1. ✓'},{title:'Euler\'s totient',body:'φ(n) = count of integers 1..n coprime to n. φ(12)=4: {1,5,7,11}.'}], explanation:'RSA encryption uses these theorems for internet security.', exercises:[{question:'3¹² mod 13 = ? (p=13 prime)',answer:'1',hint:'FLT: 3¹²≡1 (mod 13).'},{question:'φ(8) = ?',answer:'4',hint:'Coprime to 8: {1,3,5,7}.'},{question:'Why is Fermat\'s Little Theorem important for encryption?',answer:'It makes certain modular computations predictable and efficient',hint:'RSA key generation uses it.'}]},
  { id:'calculus-trig-derivatives', title:'Derivatives of Trig Functions', grade:'912', gradeLabel:'9–12', subject:'calculus', tags:['trig derivatives','sin cos tan','differentiate','chain rule'], summary:'Differentiate trigonometric functions and their compositions.', intro:'Trig functions have specific derivatives: d/dx[sin x]=cos x, d/dx[cos x]=-sin x.', steps:[{title:'Basic derivatives',body:'d/dx[sin x]=cos x. d/dx[cos x]=-sin x. d/dx[tan x]=sec²x.'},{title:'With chain rule',body:'d/dx[sin(2x)]=2cos(2x).'},{title:'Product rule combo',body:'d/dx[x·sin x]=sin x+x·cos x.'},{title:'Second derivatives',body:'d²/dx²[sin x]=-sin x. Derivative cycles with period 4.'}], explanation:'The derivative of sin being cos is why radians must be used in calculus.', exercises:[{question:'d/dx[cos(3x)]=?',answer:'-3sin(3x)',hint:'Chain rule.'},{question:'d/dx[x²cos x]=?',answer:'2x cos x - x² sin x',hint:'Product rule.'},{question:'d/dx[tan(5x)]=?',answer:'5sec²(5x)',hint:'Chain rule with tan.'}]},
  { id:'analytic-geometry', title:'Analytic Geometry: Lines and Circles', grade:'912', gradeLabel:'9–12', subject:'geometry', tags:['analytic geometry','line equation','circle equation','intersection','distance'], summary:'Use equations to analyze lines and circles in the coordinate plane.', intro:'Analytic geometry combines algebra and geometry — every geometric statement becomes an equation.', steps:[{title:'Line forms',body:'Slope-intercept: y=mx+b. Standard: ax+by=c. Point-slope: y-y₁=m(x-x₁).'},{title:'Circle equation',body:'(x-h)²+(y-k)²=r². Center (h,k), radius r.'},{title:'Distance from point to line',body:'d=|ax₀+by₀+c|/√(a²+b²).'},{title:'Intersection',body:'Solve system: line + circle equation simultaneously.'}], explanation:'Descartes connected geometry and algebra in 1637 — the bridge that made calculus possible.', exercises:[{question:'Circle center (2,-3), radius 5. Equation?',answer:'(x-2)²+(y+3)²=25',hint:'Standard form.'},{question:'Distance from (3,4) to line 3x+4y=0?',answer:'5',hint:'|9+16|/5=25/5=5.'},{question:'Line y=x intersects circle x²+y²=8. Points?',answer:'(2,2) and (-2,-2)',hint:'2x²=8 → x=±2.'}]},
  { id:'limits-continuity', title:'Limits and Continuity', grade:'912', gradeLabel:'9–12', subject:'calculus', tags:['limits','continuity','removable','jump','infinite','discontinuity'], summary:'Classify discontinuities and apply the formal definition of continuity.', intro:'A function is continuous at a if lim(x→a)f(x)=f(a). Discontinuities have types.', steps:[{title:'Three continuity conditions',body:'f(a) is defined. lim f(x) exists. Limit = f(a).'},{title:'Removable discontinuity',body:'Hole in graph: limit exists but f(a) is undefined or wrong. (x²-4)/(x-2) at x=2.'},{title:'Jump discontinuity',body:'Left and right limits exist but are different. Piecewise functions.'},{title:'Infinite discontinuity',body:'Vertical asymptote: 1/x at x=0.'}], explanation:'Continuous functions behave predictably — the Intermediate Value Theorem requires continuity.', exercises:[{question:'f(x)=(x²-1)/(x-1) at x=1. Discontinuity type?',answer:'Removable (hole at x=1)',hint:'Factor: (x+1)(x-1)/(x-1)=x+1.'},{question:'f(x)={1 if x<0; 2 if x≥0} at x=0. Type?',answer:'Jump discontinuity',hint:'Left limit≠right limit.'},{question:'1/x at x=0. Type?',answer:'Infinite discontinuity',hint:'Vertical asymptote.'}]},
  { id:'multivariable-intro', title:'Introduction to Multivariable Functions', grade:'912', gradeLabel:'9–12', subject:'calculus', tags:['multivariable','partial derivative','surface','z=f(x,y)'], summary:'Evaluate multivariable functions and find partial derivatives.', intro:'A function of two variables, z=f(x,y), produces a surface in 3D space.', steps:[{title:'Evaluate',body:'f(x,y)=x²+3xy-y². f(2,1)=4+6-1=9.'},{title:'Partial derivative ∂f/∂x',body:'Treat y as constant. ∂/∂x[x²+3xy-y²]=2x+3y.'},{title:'Partial derivative ∂f/∂y',body:'Treat x as constant. ∂/∂y[x²+3xy-y²]=3x-2y.'},{title:'Gradient',body:'∇f=(∂f/∂x, ∂f/∂y) — points in direction of steepest ascent.'}], explanation:'Partial derivatives are the foundation of machine learning gradient descent.', exercises:[{question:'f(x,y)=x³+2y². f(2,3)?',answer:'8+18=26',hint:'8+2×9.'},{question:'∂/∂x[3x²y+y³]=?',answer:'6xy',hint:'Treat y as constant.'},{question:'∂/∂y[e^(xy)]=?',answer:'xe^(xy)',hint:'Chain rule, x is constant.'}]},
  { id:'statistics-anova-intro', title:'Introduction to ANOVA', grade:'912', gradeLabel:'9–12', subject:'statistics', tags:['ANOVA','F test','variance','multiple groups','between within'], summary:'Use ANOVA to compare means across multiple groups.', intro:'ANOVA (Analysis of Variance) tests whether three or more group means are equal.', steps:[{title:'When to use',body:'Compare 3+ group means. H₀: all means equal. H₁: at least one differs.'},{title:'F statistic',body:'F = between-group variance / within-group variance.'},{title:'Interpretation',body:'Large F → differences are larger than expected by chance → reject H₀.'},{title:'Post-hoc tests',body:'If ANOVA rejects H₀, use Tukey or Bonferroni to find which pairs differ.'}], explanation:'ANOVA generalizes the two-sample t-test to multiple groups without inflating Type I error.', exercises:[{question:'Three groups same mean. F statistic?',answer:'≈0 (no between-group variation)',hint:'Numerator ≈ 0.'},{question:'F=12.3, critical value=3.89. Conclusion?',answer:'Reject H₀ — significant difference among groups',hint:'12.3>3.89.'},{question:'Why not do multiple t-tests instead of ANOVA?',answer:'Each test has 5% error chance — multiple tests compound error rate',hint:'Multiple comparisons inflate α.'}]},
];